mapper.select:
	   
       SELECT COUNT(TIH.ITEMID) AS CNT
  		 FROM XBOLTADM.TW_ITEM_HIER TIH	  
		    
		    	 INNER JOIN XBOLTADM.TB_ITEM_DIM TID ON TIH.ItemID = TID.ItemID
		    	
		 
		    
		    	TIH.ItemTypeCode = #{itemTypeCode} 
		    
		    
		    	 AND TID.DimValueID = #{dimValue}
		    	
		    
		    	 AND TIH.ItemClassCode = #{itemClassCode}
		    	
		    
		    	 AND TIH.OwnerTeamID = #{teamID}
		    	
		    
		    	 AND TIH.AuthorID = #{authorID}
		    	
		    
		    	 AND TIH.L0ItemID = #{l0ItemID}
		    	
		    
		    	 AND TIH.L1ItemID = #{l1ItemID}
		    	
		    
		    	 AND TIH.L2ItemID = #{l2ItemID}

SELECT RNUM , 0 AS CHK , ItemTypeImg , ItemID, Path, ItemName, ClassName, ClassCode, TeamName , OwnerTeamName, Name, LastUpdated,Version, Identifier, CSVersion , ProcessInfo , ItemTypeName , ValidFrom , StatusName , 'btn_import_small.gif' As Report , CreationTime , L0Name , L1Name , L2Name , L3Name , L4Name , FileIcon , SeqLevel , AuthorID , Comment FROM ( SELECT Row_Number()OVER(ORDER BY TI.Identifier, TI.ClassCode) as RNUM , TI.ItemID , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , TIH.Path AS Path , ISNULL(TIA.PlainText,'') as ItemName , TD.Name as ClassName, TI.ClassCode , ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , TM.Name , TI.Version , TI.Identifier , TIAF.PlainText as ProcessInfo , TSD.Name AS StatusName , TID.Name AS ItemTypeName , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , Convert(nvarchar(20),TI.CreationTime, 111) AS CreationTime , Convert(nvarchar(20),TCS.ValidFrom, 111) AS ValidFrom , TCS.Version AS CSVersion , '' AS L0Name , ISNULL((SELECT PlainText FROM XBOLTADM.TB_ITEM_ATTR WHERE ItemID = TIH.L1ItemID AND AttrTypeCode = 'AT00001' AND LanguageID = #{languageID}),'') AS L1Name , ISNULL((SELECT PlainText FROM XBOLTADM.TB_ITEM_ATTR WHERE ItemID = TIH.L2ItemID AND AttrTypeCode = 'AT00001' AND LanguageID = #{languageID}),'') AS L2Name , '' AS L3Name , '' AS L4Name , CASE WHEN ISNULL(TIFF.DocumentID , '') != '' THEN 'icon_attach.png' ELSE 'blank.gif' END FileIcon , TIA3.plainText AS SeqLevel , TIA4.plainText AS Comment , TI.AuthorID AS AuthorID , TIS.SortNum , (Select Count(*) From XBOLTADM.TB_MY_ITEM Where ItemID = TI.ItemID And MemberID = #{sessionUserID} And AssignMentType = #{assignmentType} ) AS myItemCnt FROM XBOLTADM.TB_ITEM TI INNER JOIN XBOLTADM.TB_ITEM TIS ON TIS.ToItemID = TI.ItemID AND TIS.CategoryCode = 'ST1' LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TID on TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.ZITEM_ATTR_VIEW TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.ZITEM_ATTR_VIEW TIAF on TI.ItemID = TIAF.ItemID AND TIAF.AttrTypeCode = 'AT00003' AND TIAF.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.ZITEM_ATTR_VIEW TIA2 on TI.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00053' AND TIA2.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.ZITEM_ATTR_VIEW TIA4 on TI.ItemID = TIAF.ItemID AND TIA4.AttrTypeCode = 'AT00006' AND TIA4.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.ZITEM_ATTR_VIEW TIA3 on TI.ItemID = TIA3.ItemID AND TIA3.AttrTypeCode = 'AT00040' AND TIA3.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS on CASE WHEN ISNULL(TI.ReleaseNo,'0') = '0' THEN TI.CurChangeSet ELSE TI.ReleaseNo END = TCS.ChangeSetID LEFT OUTER JOIN (SELECT DISTINCT DocumentID FROM XBOLTADM.TB_FILE Where DocCategory = 'ITM' AND Blocked != 1) TIFF ON TI.ItemID = TIFF.DocumentID LEFT OUTER JOIN XBOLTADM.TW_ITEM_HIER TIH ON TI.ItemID = TIH.ItemID
INNER JOIN (SELECT TIC.Level , CXI.ItemID FROM XBOLTADM.TB_ITEM CXI INNER JOIN XBOLTADM.TB_ITEM_CLASS TIC ON CXI.ClassCode = TIC.ItemClassCode WHERE CXI.ITEMID = #{s_itemID}) CXL ON ( CASE CXL.Level WHEN 0 THEN TIH.L0ItemID WHEN 1 THEN TIH.L1ItemID WHEN 2 THEN TIH.L2ItemID WHEN 3 THEN TIH.L3ItemID WHEN 4 THEN TIH.L4ItemID WHEN 5 THEN TIH.L5ItemID ELSE '' END ) = CXL.ITEMID
LEFT OUTER JOIN XBOLTADM.TB_ITEM_DIM TIDM ON TI.ItemID = TIDM.ItemID
AND TIDM.DimTypeID = #{DimTypeID}
Inner Join XBOLTADM.TB_MY_ITEM TMI ON TI.ItemID = TMI.ItemID AND TMI.MemberID = #{markAuthorID} AND TMI.AssignmentType = 'SUBSCR' AND TMI.AccessRight = 'R'
WHERE TI.Deleted != 1 And TIA.ItemID != ''
AND TI.CategoryCode != 'TOJ'
AND (1=1
${item.selectOption} TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.ZITEM_ATTR_VIEW WHERE AttrTypeCode = #{item.attrCode}
AND REPLACE(PlainText,' ','')
NOT like replace('%'+#{item.searchValue}+'%', ' ','')
AND REPLACE(PlainText,' ','')
not like replace('%'+#{item.searchValue}+'%'ESCAPE'!', ' ','')
AND LanguageID = #{languageID}
AND LanguageID = #{defaultLang}
)
${item.selectOption} TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.ZITEM_ATTR_VIEW WHERE LovCode IN (
#{item2}
) AND AttrTypeCode = #{item.attrCode}
AND LanguageID = #{languageID}
AND LanguageID = #{defaultLang}
)
${item.selectOption} TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE Identifier
not
like '%'+#{item.searchValue}+'%' )
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.ZITEM_ATTR_VIEW WHERE AttrTypeCode = #{item.attrCode} AND LanguageID = #{languageID}
AND ClassCode = #{ClassCode}
AND ItemID IN(${childItems})
AND ItemID IN ('')
)
AND TI.ItemID NOT IN ( SELECT ItemID FROM XBOLTADM.ZITEM_ATTR_VIEW WHERE AttrTypeCode = #{item.attrCode} AND LanguageID = #{languageID}
AND ClassCode = #{ClassCode}
AND ItemID IN (${childItems})
AND ItemID IN ('')
)
)
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.ZITEM_ATTR_VIEW WHERE REPLACE(PlainText,' ','') like REPLACE('%'+#{baseCondition1}+'%',' ','') AND AttrTypeCode = #{AttrCodeBase1} AND LanguageID = #{languageID} )
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE
Identifier like '%'+#{baseCondition2}+'%'ESCAPE'!' Identifier like '%'+#{baseCondition2}+'%'
)
AND TI.CategoryCode = #{CategoryCode}
AND TI.ClassCode = #{ClassCode}
AND TI.ClassCode IN ( ${ClassCodeList} )
AND TI.ItemTypeCode = #{ItemTypeCode}
AND TI.ItemID IN (${childItems})
AND TI.ItemID IN ('')
AND TI.ItemID NOT IN (${masterItemId})
AND TIDM.DimValueID IN (
#{item}
)
AND TIDM.DimTypeID = #{DimTypeID}
AND TIDM.DimValueID IS NULL
AND TI.CompanyID = #{CompanyID}
AND TOT.Name like '%'+#{OwnerTeam}+'%'ESCAPE'!'
AND TOT.Name like '%'+#{OwnerTeam}+'%'
AND TM.Name like '%'+#{Name}+'%'ESCAPE'!'
AND TM.Name like '%'+#{Name}+'%'
AND TI.Status = #{Status}
AND TI.Identifier IS NOT NULL AND TI.Identifier != ''
AND CONVERT(nvarchar(20), TI.CreationTime, 112) BETWEEN #{scStartDt1} AND #{scEndDt1}
AND CONVERT(nvarchar(20), TI.LastUpdated, 112) BETWEEN #{scStartDt2} AND #{scEndDt2}
AND DATEDIFF(YY,TI.LastUpdated,GETDATE()) > 1 AND TI.ClassCode IN (${ClassCodes}) AND TI.ItemTypeCode IN (${ItemTypeCodes})
And TI.AuthorID = #{sessionUserId}
) A 1=1
AND A.RNUM BETWEEN ((${pageNo}-1)*${LIST_PAGE_SCALE} + 1) AND (${pageNo}*${LIST_PAGE_SCALE})
AND ItemID NOT IN (select ItemID FROM XBOLTADM.TB_ITEM_DIM WHERE DimTypeID = #{DimTypeID})
Order By SortNum, Identifier, ClassCode

	   
       SELECT ISNULL(COUNT(FileCount),0) AS CNT
  		 FROM XBOLTADM.TW_ITEM_HIER
		 WHERE ItemID = #{itemID}

	   
       SELECT ISNULL(COUNT(ItemID),0) AS CNT
  		 FROM XBOLTADM.TW_ITEM_HIER
		 WHERE ItemID = #{itemID} AND L0ItemID = #{l0ItemID}

Select
Top ${maxListCount}
Top 1000
Row_Number() OVER(ORDER BY TI.LastUpdated DESC,TI.ItemTypeCode ASC, TI.Identifier ASC, TIA.PlainText ASC ) AS RNUM
, CASE WHEN TIP.ItemID IS NOT NULL THEN 1 ELSE 0 END AS CHK
, 0 AS CHK
, ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , TI.Identifier , ISNULL(TIA.PlainText,'') As ItemNM , TDC.Name AS ClassName , TI.ClassCode , TI.ItemTypeCode , ISNULL(PJTXT.Name,'') AS PjtName , ISNULL(TOT.Name,'') AS OwnerTeamName , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End AS AuthorName , ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID, #{languageID}),'') AS Path , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated ,Case TI.Status When 'NEW1' Then TDS.Name When 'MOD1' Then TDS.Name When 'MOD2' Then TDS.Name ELSE TDS.Name END AS StatusNM , ISNULL(TDI.Name,'') AS ItemTypeName , TI.Status , TI.ItemID , TI.Blocked , TCS.Status AS csStatus, TCS.ChangeSetID, TDCT.Name AS ChangeTypeNM, TCS.ChangeType , TCLS.DefCSRID , CASE WHEN TCLS.ChangeMgt = '1' Then 'Yes' Else 'No' End ChangeMgtYN , CASE WHEN TI.Status = 'MOD2' OR TI.Status = 'NEW2' OR TI.Status = 'DEL2' Then '<button type=button class=gridBtn >View</button>' Else '<button type=button class=gridBtn >Edit</button>' End AS editIcon , ISNULL(TCS.Version,'') AS Version , Convert(nvarchar(20),ISNULL(TCS.ValidFrom,TI.LastUpdated), 111) AS ValidFrom From XBOLTADM.TB_ITEM TI Left Outer Join XBOLTADM.TB_Item_Attr TIA ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDC ON TDC.TypeCode = TI.ClassCode AND TDC.Category = 'CLS' And TDC.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_PROJECT CSR ON CSR.ProjectID = TI.ProjectID LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT PJTXT ON PJTXT.ProjectID = CSR.RefPjtID and PJTXT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS ON TCLS.ItemClassCode = TI.ClassCode Left Outer Join XBOLTADM.TB_DICTIONARY TDI ON TDI.TypeCode = TI.ItemTypeCode And TDI.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDS ON TI.Status = TDS.TypeCode AND TDS.Category = 'ITMSTS' AND TDS.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TCS.ItemID = TI.ItemID AND TCS.ChangeSetID = TI.CurChangeSet Left Outer Join XBOLTADM.TB_DICTIONARY TDCT ON TDCT.TypeCode = TCS.ChangeType AND TDCT.Category = 'CNGT1' And TDCT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_PROPOSAL TIP ON TI.ItemID = TIP.ItemID
LEFT OUTER JOIN XBOLTADM.TB_MY_ITEM TMI ON TI.ItemID = TMI.ItemID AND TMI.MemberID = #{sessionUserId}
AND TIP.SRID = #{srID}
Where TI.Deleted != 1 AND TI.CategoryCode In ('OJ', 'TOJ') AND TI.CategoryCode != 'TOJ'
And TI.AuthorID = #{sessionUserId}
And (TI.AuthorID = #{sessionUserId} OR (TMI.MemberID = #{sessionUserId} AND TMI.AssignmentType = 'CNGROLETP' AND TMI.Assigned = '1'
AND TMI.RoleType = #{roleType}
))
And TI.OwnerTeamID IN ( select TeamID from [XBOLTADM].[fn_GetSubTeamList] (#{sessionTeamId}))
And TI.OwnerTeamID = #{sessionTeamId}
And TI.AuthorID = #{authorID}
And TI.OwnerTeamID IN ( select TeamID from [XBOLTADM].[fn_GetSubTeamList] (#{ownerTeamID}))
And TI.OwnerTeamID = #{ownerTeamID}
And TIP.ItemID IS NOT NULL
And TI.ItemTypeCode = #{itemTypeCode}
And TI.ClassCode IN (${itemClassCodes})
And TI.ItemTypeCode IN (${itemTypeCodes})
And TI.ClassCode = #{classCode}
And TI.Status IN (${statusList})
And (TI.Status = 'REL' OR (TI.Status = 'NEW1' AND TIP.ItemID IS NOT NULL)) AND TI.ItemID NOT IN (SELECT ItemID FROM XBOLTADM.TB_ITEM_PROPOSAL WHERE srID != #{srID})
And TI.Status != 'REL' AND TIP.ItemID IS NULL
And TI.Status = #{status} AND TIP.ItemID IS NULL
AND TIA.PlainText like N'%'+#{searchValue}+'%'
AND TI.Identifier Like N'%'+#{searchValue}+'%'
AND TCLS.ChangeMgt = '1' AND TCS.ChangeSetID IS NOT NULL
AND TCLS.ChangeMgt = '0'
Order By TI.LastUpdated DESC, ItemTypeCode, Identifier , ItemNM

Select
Top ${maxListCount}
Top 1000
Row_Number() OVER(ORDER BY TI.LastUpdated DESC,TI.ItemTypeCode ASC, TI.Identifier ASC, TIA.PlainText ASC ) AS RNUM
, CASE WHEN TIP.ItemID IS NOT NULL THEN 1 ELSE 0 END AS CHK
, 0 AS CHK
, ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , TI.Identifier , ISNULL(TIA.PlainText,'') As ItemNM , TDC.Name AS ClassName , TI.ClassCode , TI.ItemTypeCode , ISNULL(PJTXT.Name,'') AS PjtName , ISNULL(TOT.Name,'') AS OwnerTeamName , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End AS AuthorName , ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID, #{languageID}),'') AS Path , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated ,Case TI.Status When 'NEW1' Then TDS.Name When 'MOD1' Then TDS.Name When 'MOD2' Then TDS.Name ELSE TDS.Name END AS StatusNM , ISNULL(TDI.Name,'') AS ItemTypeName , TI.Status , TI.ItemID , TI.Blocked , TCS.Status AS csStatus, TCS.ChangeSetID, TDCT.Name AS ChangeTypeNM, TCS.ChangeType , TCLS.DefCSRID , CASE WHEN TCLS.ChangeMgt = '1' Then 'Yes' Else 'No' End ChangeMgtYN , CASE WHEN TI.Status = 'MOD2' OR TI.Status = 'NEW2' OR TI.Status = 'DEL2' Then '<button type=button class=gridBtn >View</button>' Else '<button type=button class=gridBtn >Edit</button>' End AS editIcon
From XBOLTADM.TB_ITEM TI Left Outer Join XBOLTADM.TB_Item_Attr TIA ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDC ON TDC.TypeCode = TI.ClassCode AND TDC.Category = 'CLS' And TDC.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_PROJECT CSR ON CSR.ProjectID = TI.ProjectID LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT PJTXT ON PJTXT.ProjectID = CSR.RefPjtID and PJTXT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TOT ON TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TI.AuthorID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS ON TCLS.ItemClassCode = TI.ClassCode Left Outer Join XBOLTADM.TB_DICTIONARY TDI ON TDI.TypeCode = TI.ItemTypeCode And TDI.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDS ON TI.Status = TDS.TypeCode AND TDS.Category = 'ITMSTS' AND TDS.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_CHANGE_SET TCS ON TCS.ItemID = TI.ItemID AND TCS.ChangeSetID = TI.CurChangeSet Left Outer Join XBOLTADM.TB_DICTIONARY TDCT ON TDCT.TypeCode = TCS.ChangeType AND TDCT.Category = 'CNGT1' And TDCT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_PROPOSAL TIP ON TI.ItemID = TIP.ItemID
LEFT OUTER JOIN XBOLTADM.TB_MY_ITEM TMI ON TI.ItemID = TMI.ItemID AND TMI.MemberID = #{sessionUserId}
AND TIP.SRID = #{srID}
Where TI.Deleted != 1 AND TI.CategoryCode In ('OJ', 'TOJ') AND TI.CategoryCode != 'TOJ'
And TI.AuthorID = #{sessionUserId}
And (TI.AuthorID = #{sessionUserId} OR (TMI.MemberID = #{sessionUserId} AND TMI.AssignmentType = 'CNGROLETP' AND TMI.Assigned = '1'
AND TMI.RoleType = #{roleType}
))
And TI.OwnerTeamID IN ( select TeamID from [XBOLTADM].[fn_GetSubTeamList] (#{sessionTeamId}))
And TI.OwnerTeamID = #{sessionTeamId}
And TI.AuthorID = #{authorID}
And TI.OwnerTeamID IN ( select TeamID from [XBOLTADM].[fn_GetSubTeamList] (#{ownerTeamID}))
And TI.OwnerTeamID = #{ownerTeamID}
And TIP.ItemID IS NOT NULL
And TI.ItemTypeCode = #{itemTypeCode}
And TI.ClassCode IN (${itemClassCodes})
And TI.ItemTypeCode IN (${itemTypeCodes})
And TI.ClassCode = #{classCode}
And TI.Status IN (${statusList})
And (TI.Status = 'REL' OR (TI.Status = 'NEW1' AND TIP.ItemID IS NOT NULL)) AND TI.ItemID NOT IN (SELECT ItemID FROM XBOLTADM.TB_ITEM_PROPOSAL WHERE srID != #{srID})
And TI.Status != 'REL' AND TIP.ItemID IS NULL
And TI.Status = #{status} AND TIP.ItemID IS NULL
AND TIA.PlainText like N'%'+#{searchValue}+'%'
AND TI.Identifier Like N'%'+#{searchValue}+'%'
AND TCLS.ChangeMgt = '1'
AND TCLS.ChangeMgt = '0'
Order By TI.LastUpdated DESC, ItemTypeCode, Identifier , ItemNM

WITH StaffTree AS ( SELECT '0' AS PRE_TREE_ID, '15' AS TREE_ID, (SELECT NAME FROM XBOLTADM.TB_DICTIONARY WHERE TypeCode = 'LN00018' AND LanguageID = #{sessionCurrLangType}) AS TREE_NM, 0 AS SortNum UNION ALL
SELECT C.ParentID AS PRE_TREE_ID , C.TeamID AS TREE_ID , Convert(nvarchar(1000),D.Name) AS TREE_NM , c.SortNum FROM XBOLTADM.TB_TEAM C, XBOLTADM.TB_TEAM_TXT D WHERE C.TeamID = D.TeamID AND C.Deleted != '1' AND D.LanguageID = #{sessionCurrLangType} AND C.TeamID in ( SELECT DISTINCT OwnerTeamID FROM XBOLTADM.TB_ITEM WHERE Deleted != 1 AND CategoryCode = 'OJ'
AND ItemTypeCode = #{defItemTypeCode}
AND ClassCode in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included = 'Y' )
) AND TeamType Not In ( '1', '2') UNION ALL
SELECT CASE ss.ParentID When 1 Then '-1' Else ss.ParentID END AS PRE_TREE_ID, ss.TeamID AS TREE_ID, Convert(nvarchar(1000),DD.Name) AS TREE_NM , ss.SortNum FROM XBOLTADM.TB_TEAM ss INNER JOIN StaffTree t ON t.PRE_TREE_ID = ss.TeamID, XBOLTADM.TB_TEAM_TXT DD WHERE ss.TeamID = DD.TeamID AND ss.Deleted != '1' AND DD.LanguageID = #{sessionCurrLangType} AND ss.ParentID != 0 ) SELECT DISTINCT PRE_TREE_ID, TREE_ID, TREE_NM, SortNum FROM StaffTree ORDER BY SortNum , TREE_NM
